INSERT INTO `games` (`id`, `title`, `developer`, `publisher`, `about`, `release_date`, `cover_img`, `icon`, `steam_rating`) VALUES
(10, 'Counter-Strike', 'Valve', 'Valve', 'Play the world\'s number 1 online action game. Engage in an incredibly realistic brand of terrorist warfare in this wildly popular team-based game. Ally with teammates to complete strategic missions. Take out enemy sites. Rescue hostages. Your role affects your team\'s success. Your team\'s success affects your role.', '2000-11-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/10/header.jpg?t=1745368572', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/10/capsule_231x87.jpg?t=1745368572', '4'),
(550, 'Left 4 Dead 2', 'Valve', 'Valve', 'Set in the zombie apocalypse, Left 4 Dead 2 is a co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.', '2009-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/550/header.jpg?t=1772742214', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/550/capsule_231x87.jpg?t=1772742214', '4'),
(4000, 'Garry\'s Mod', 'Facepunch Studios', 'Valve', 'Garry\'s Mod is a physics sandbox. There aren\'t any predefined aims or goals. We give you the tools and leave you to play.', '2006-11-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4000/header.jpg?t=1776868682', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4000/2e52d9b905feebfdaaf2db6ad7afece10991d504/capsule_231x87.jpg?t=1776868682', '4'),
(12100, 'Grand Theft Auto III', 'Rockstar Games', 'Rockstar Games', 'Welcome to Liberty City. Where it all began. With stellar voice acting, a darkly comic storyline, a stunning soundtrack and revolutionary open-world gameplay, Grand Theft Auto III is the game that defined the open world genre for a generation.', '2008-01-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/12100/header.jpg?t=1634144440', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/12100/capsule_231x87.jpg?t=1634144440', '5'),
(12120, 'Grand Theft Auto: San Andreas', 'Rockstar Games', 'Rockstar Games', 'Five years ago Carl Johnson escaped from the pressures of life in Los Santos, San Andreas... a city tearing itself apart with gang trouble, drugs and corruption. Where filmstars and millionaires do their best to avoid the dealers and gangbangers. Now, it\'s the early 90s. Carl\'s got to go home.', '2008-01-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/12120/header.jpg?t=1634144450', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/12120/capsule_231x87.jpg?t=1634144450', '5'),
(21000, 'LEGO® Batman™: The Videogame', 'Traveller\'s Tales', 'Warner Bros. Interactive Enter', 'When all the villains in Arkham Asylum team up and break loose, only the dynamic duo is bold enough to take them on to save Gotham City. The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame.', '2008-09-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/21000/header.jpg?t=1752107972', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/21000/capsule_231x87.jpg?t=1752107972', '4'),
(39210, 'FINAL FANTASY XIV Online', 'Square Enix', 'Square Enix', 'Join over 30 million adventurers worldwide and take part in an epic and ever-changing FINAL FANTASY. Experience an unforgettable story, exhilarating battles, and a myriad of captivating environments to explore.', '2014-02-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/39210/header.jpg?t=1777372469', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/39210/2e45b2f419d0beed57ba1ff1d80a13d31f947d54/capsule_231x87.jpg?t=1777372469', '4'),
(47870, 'Need For Speed: Hot Pursuit', 'Criterion Games', 'Electronic Arts', 'Need for Speed Hot Pursuit launches you into a new open-world landscape behind the wheel of the world\'s fastest and most beautiful cars. From Criterion, the award-winning studio behind the Burnout series, Hot Pursuit will redefine racing games for a whole new generation.', '2010-12-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/47870/header.jpg?t=1743805492', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/47870/capsule_231x87.jpg?t=1743805492', '4'),
(50130, 'Mafia II (Classic)', '2K Czech', '2K', 'Vito Scaletta has started to make a name for himself on the streets of Empire Bay as someone who can be trusted to get a job done. Together with his buddy Joe, he is working to prove himself to the Mafia, quickly escalating up the family ladder with crimes of larger reward, status and consequence… the life as a wise guy isn’t quite as...', '2011-03-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/50130/header.jpg?t=1746717708', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/50130/capsule_231x87.jpg?t=1746717708', '4'),
(57300, 'Amnesia: The Dark Descent', 'Frictional Games', 'Frictional Games', 'Amnesia: The Dark Descent, a first person survival horror. A game about immersion, discovery and living through a nightmare. An experience that will chill you to the core.', '2010-09-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/57300/header.jpg?t=1751032707', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/57300/ce0f84d25ace136096191d215a5d49c57d832999/capsule_231x87.jpg?t=1751032707', '4'),
(105600, 'Terraria', 'Re-Logic', 'Re-Logic', 'Dig, fight, explore, build! Nothing is impossible in this action-packed adventure game. Four Pack also available!', '2011-05-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/105600/header.jpg?t=1769844435', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/105600/capsule_231x87.jpg?t=1769844435', '4'),
(108600, 'Project Zomboid', 'The Indie Stone', 'The Indie Stone', 'Project Zomboid is the ultimate in zombie survival. Alone or in MP: you loot, build, craft, fight, farm and fish in a struggle to survive. A hardcore RPG skillset, a vast map, massively customisable sandbox and a cute tutorial raccoon await the unwary. So how will you die? All it takes is a bite..', '2013-11-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/108600/header.jpg?t=1777298596', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/108600/capsule_231x87.jpg?t=1777298596', '4'),
(203160, 'Tomb Raider Game of the Year', 'Crystal Dynamics, Eidos-Montré', 'Crystal Dynamics, Feral Intera', 'Tomb Raider explores the intense origin story of Lara Croft and her ascent from a young woman to a hardened survivor.', '2013-03-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/203160/9e67774e97cdd155f287146e62611eb445514ac6/header.jpg?t=1765220424', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/203160/2155072e0f151e8bd3fe142cfcb2397d8b30f026/capsule_231x87.jpg?t=1765220424', '4'),
(207140, 'SpeedRunners', 'DoubleDutch Games', 'tinyBuild', 'Cut-throat multiplayer running game that pits 4 players against each other, locally and/or online. Run, jump, swing around, and use devious weapons and pick-ups to knock opponents off-screen! One of the most competitive games you\'ll ever play.', '2016-04-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/207140/header.jpg?t=1777391860', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/207140/capsule_231x87.jpg?t=1777391860', '4'),
(220200, 'Kerbal Space Program', 'Squad', 'Private Division', 'In Kerbal Space Program, take charge of the space program for the alien race known as the Kerbals. You have access to an array of parts to assemble fully-functional spacecraft that flies (or doesn’t) based on realistic aerodynamic and orbital physics.', '2015-04-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/220200/header.jpg?t=1738037585', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/220200/capsule_231x87.jpg?t=1738037585', '4'),
(221100, 'DayZ', 'Bohemia Interactive', 'Bohemia Interactive', 'How long can you survive a post-apocalyptic world? A land overrun with an infected &quot;zombie&quot; population, where you compete with other survivors for limited resources. Will you team up with strangers and stay strong together? Or play as a lone wolf to avoid betrayal? This is DayZ – this is your story.', '2018-12-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/221100/header.jpg?t=1769695513', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/221100/capsule_231x87.jpg?t=1769695513', '4'),
(227300, 'Euro Truck Simulator 2', 'SCS Software', 'SCS Software', 'Travel across Europe as king of the road, a trucker who delivers important cargo across impressive distances! With dozens of cities to explore, your endurance, skill and speed will all be pushed to their limits.', '2012-10-12', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227300/9a81dc3126c56637297b654f9dcac057cfd79b77/header.jpg?t=1773641450', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227300/da84d11d3ddd817e0cca299608b469a854d75ba5/capsule_231x87.jpg?t=1773641450', '4'),
(227940, 'Heroes & Generals', 'TLM Partners', 'TLM Partners', 'Shoot, blow sh!t up, fly or bark orders in the ultimate Free-to-Play, large scale, multiplayer, shooter experience. Thousands of players in multiple battles fighting one massive war of nations. The first to capture 15 cities takes the glory.', '2016-10-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227940/header.jpg?t=1685049235', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227940/capsule_231x87.jpg?t=1685049235', '4'),
(234140, 'Mad Max', 'Avalanche Studios', 'Warner Bros. Games, Warner Bro', 'Play as Mad Max, a reluctant hero and survivor who wants nothing more than to leave the madness behind and find solace.', '2015-09-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/234140/header.jpg?t=1773442092', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/234140/capsule_231x87.jpg?t=1773442092', '3'),
(241930, 'Middle-earth™: Shadow of Mordor™', 'Monolith Productions', 'Warner Bros. Interactive Enter', 'Fight through Mordor and uncover the truth of the spirit that compels you, discover the origins of the Rings of Power, build your legend and ultimately confront the evil of Sauron in this new chronicle of Middle-earth.', '2014-09-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/241930/header.jpg?t=1757538323', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/241930/capsule_231x87.jpg?t=1757538323', '4'),
(242050, 'Assassin’s Creed® IV Black Flag™', 'Ubisoft Montreal', 'Ubisoft', 'Discover Assassin\'s Creed IV Black Flag, the classic pirate action-adventure game from 2013. Command your ship, hunt Templars and carve your legend as Edward Kenway across the Caribbean\'s Golden Age of Piracy.', '2026-05-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/242050/header.jpg?t=1777052740', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/242050/capsule_231x87.jpg?t=1777052740', '4'),
(242760, 'The Forest', 'Endnight Games Ltd', 'Endnight Games Ltd', 'As the lone survivor of a passenger jet crash, you find yourself in a mysterious forest battling to stay alive against a society of cannibalistic mutants. Build, explore, survive in this terrifying first person survival horror simulator.', '2018-04-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/242760/header.jpg?t=1699381053', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/242760/capsule_231x87.jpg?t=1699381053', '4'),
(244210, 'Assetto Corsa', 'Kunos Simulazioni', 'Kunos Simulazioni', 'Assetto Corsa v1.16 introduces the new &quot;Laguna Seca&quot; laser-scanned track, 7 new cars among which the eagerly awaited Alfa Romeo Giulia Quadrifoglio! Check the changelog for further info!', '2014-12-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/244210/header.jpg?t=1754985171', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/244210/d63fc060c13548861637663b085339a4d9a37781/capsule_231x87.jpg?t=1754985171', '4'),
(250900, 'The Binding of Isaac: Rebirth', 'Nicalis, Inc., Edmund McMillen', 'Nicalis, Inc.', 'The Binding of Isaac: Rebirth is a randomly generated action RPG shooter with heavy Rogue-like elements. Following Isaac on his journey players will find bizarre treasures that change Isaac’s form giving him super human abilities and enabling him to fight off droves of mysterious creatures, discover secrets and fight his way to safety.', '2014-11-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/250900/header.jpg?t=1731977365', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/250900/capsule_231x87.jpg?t=1731977365', '4'),
(251570, '7 Days to Die', 'The Fun Pimps', 'The Fun Pimps Entertainment LL', '7 Days to Die is an open-world game that is a unique combination of first-person shooter, survival horror, tower defense, and role-playing games. Play the definitive zombie survival sandbox RPG that came first. Navezgane awaits!', '2024-07-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/251570/header.jpg?t=1776457619', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/251570/capsule_231x87.jpg?t=1776457619', '4'),
(252490, 'Rust', 'Facepunch Studios', 'Facepunch Studios', 'The only aim in Rust is to survive. Everything wants you to die - the island’s wildlife, other inhabitants, the environment, and other survivors. Do whatever it takes to last another night.', '2018-02-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/header.jpg?t=1778597738', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/21aac0b6e20e1ba12f635e7deb730e32a51afbd5/capsule_231x87.jpg?t=1778597738', '3'),
(252950, 'Rocket League®', 'Psyonix LLC', 'Psyonix LLC', 'Rocket League is a high-powered hybrid of arcade-style soccer and vehicular mayhem with easy-to-understand controls and fluid, physics-driven competition. Rocket League includes casual and competitive Online Matches, a fully-featured offline Season Mode, special “Mutators” that let you change the rules entirely, hockey and...', '2015-07-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252950/1bcf75584d0c3613b02b2d0a2721a6b411375784/header_alt_assets_15.jpg?t=1773251703', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252950/1a3343801a62bfb821b407c1c237119f26d56319/capsule_231x87_alt_assets_15.jpg?t=1773251703', '4'),
(261550, 'Mount & Blade II: Bannerlord', 'TaleWorlds Entertainment', 'TaleWorlds Entertainment', 'A strategy/action RPG. Create a character, engage in diplomacy, craft, trade and conquer new lands in a vast medieval sandbox. Raise armies to lead into battle and command and fight alongside your troops in massive real-time battles using a deep but intuitive skill-based combat system.', '2022-10-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/261550/header.jpg?t=1764252300', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/261550/capsule_231x87.jpg?t=1764252300', '4'),
(264710, 'Subnautica', 'Unknown Worlds Entertainment', 'Unknown Worlds Entertainment', 'Descend into the depths of an alien underwater world filled with wonder and peril. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive.', '2018-01-23', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/264710/header.jpg?t=1777456112', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/264710/capsule_231x87.jpg?t=1777456112', '4'),
(270880, 'American Truck Simulator', 'SCS Software', 'SCS Software', 'Experience legendary American trucks and deliver various cargoes across sunny California, sandy Nevada, and the Grand Canyon State of Arizona. American Truck Simulator takes you on a journey through the breathtaking landscapes and widely recognized landmarks around the States.', '2016-02-02', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/270880/a80e5a18363259677ca96c2a39503ea595d2a45f/header.jpg?t=1778774561', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/270880/8809b200b3ebdd7fbcdbfdbe6c8f91b2c0ce93df/capsule_231x87.jpg?t=1778774561', '4'),
(271590, 'Grand Theft Auto V Legacy', 'Rockstar North', 'Rockstar Games', 'Grand Theft Auto V for PC offers players the option to explore the award-winning world of Los Santos and Blaine County in resolutions of up to 4k and beyond, as well as the chance to experience the game running at 60 frames per second.', '2015-04-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/header.jpg?t=1765387725', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/capsule_231x87.jpg?t=1765387725', '5'),
(273350, 'Evolve Stage 2', 'Turtle Rock Studios', '2K', 'Play Evolve for free with Evolve Stage 2! Evolve Stage 2 is a next-generation free multiplayer shooter featuring addictive 4v1 gameplay. One player-controlled monster must evade and outsmart a team of four uniquely skilled hunters.', '2015-02-10', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/273350/header.jpg?t=1568755531', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/273350/capsule_231x87.jpg?t=1568755531', '4'),
(284160, 'BeamNG.drive', 'BeamNG', 'BeamNG', 'A dynamic soft-body physics vehicle simulator capable of doing just about anything.', '2015-05-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/284160/17f8af1312bc48e6cd90e5fb639d4981682af260/header.jpg?t=1772048121', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/284160/727b938bf07eaf615baf2d9bb6ffebca1fa8b5d5/capsule_231x87.jpg?t=1772048121', '4'),
(286570, 'F1 2015', 'Codemasters, Feral Interactive', 'Codemasters, Feral Interactive', 'Race like a champion in F1™ 2015 A stunning new game engine and all-new ‘broadcast presentation’ puts you in the heart of the action.', '2015-07-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/286570/header.jpg?t=1647013399', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/286570/capsule_231x87.jpg?t=1647013399', '3'),
(286690, 'Metro 2033 Redux', '4A Games', 'Deep Silver', 'In 2013 the world was devastated by an apocalyptic event, annihilating almost all mankind and turning the Earth\'s surface into a poisonous wasteland. A handful of survivors took refuge in the depths of the Moscow underground, and human civilization entered a new Dark Age. The year is 2033.', '2014-08-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/286690/header.jpg?t=1741110084', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/286690/capsule_231x87.jpg?t=1741110084', '4'),
(287700, 'METAL GEAR SOLID V: THE PHANTOM PAIN', 'KONAMI', 'KONAMI', 'Ushering in a new era for the METAL GEAR franchise with cutting-edge technology powered by the Fox Engine, METAL GEAR SOLID V: The Phantom Pain, will provide players a first-rate gaming experience as they are offered tactical freedom to carry out open-world missions.', '2015-09-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/287700/header.jpg?t=1778872866', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/287700/capsule_231x87.jpg?t=1778872866', '5'),
(289070, 'Sid Meier’s Civilization® VI', 'Firaxis Games, Aspyr (Mac), As', '2K, Aspyr (Mac), Aspyr (Linux)', 'Expand your empire, advance your culture and go head-to-head against history’s greatest leaders. Will your civilization stand the test of time?', '2016-10-20', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/289070/header.jpg?t=1740607040', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/289070/capsule_231x87.jpg?t=1740607040', '4'),
(291480, 'Warface: Clutch', 'MY.GAMES', 'MY.GAMES', '𝗪𝗮𝗿𝗳𝗮𝗰𝗲: 𝗖𝗹𝘂𝘁𝗰𝗵 𝗶𝘀 𝗮 𝗰𝗼𝗻𝘁𝗲𝗺𝗽𝗼𝗿𝗮𝗿𝘆 𝗠𝗠𝗢 𝗳𝗶𝗿𝘀𝘁 𝗽𝗲𝗿𝘀𝗼𝗻 𝘀𝗵𝗼𝗼𝘁𝗲𝗿 𝘄𝗶𝘁𝗵 𝗺𝗶𝗹𝗹𝗶𝗼𝗻𝘀 𝗼𝗳 𝗳𝗮𝗻𝘀 𝗮𝗿𝗼𝘂𝗻𝗱 𝘁𝗵𝗲 𝘄𝗼𝗿𝗹𝗱. 𝗜𝘁 𝗼𝗳𝗳𝗲𝗿𝘀 𝗶𝗻𝘁𝗲𝗻𝘀𝗲 𝗣𝘃𝗣 𝗺𝗼𝗱𝗲𝘀, 𝗰𝗼𝗺𝗽𝗲𝗹𝗹𝗶𝗻𝗴 𝗣𝘃𝗘 𝗺𝗶𝘀𝘀𝗶𝗼𝗻𝘀 𝗮𝗻𝗱 𝗿𝗮𝗶𝗱𝘀 𝘁𝗵𝗮𝘁 𝘆𝗼𝘂 𝗰𝗮𝗻 𝗰𝗵𝗮𝗹𝗹𝗲𝗻𝗴𝗲 𝘄𝗶𝘁𝗵 𝗳𝗶𝘃𝗲 𝗱𝗶𝘃𝗲𝗿𝘀𝗲 𝗰𝗹𝗮𝘀𝘀𝗲𝘀 𝗮𝗻𝗱 𝗮 𝗰𝗼𝗹𝗼𝘀𝘀𝗮𝗹 𝗰𝘂𝘀𝘁𝗼𝗺𝗶𝘇𝗮𝗯𝗹𝗲 𝗮𝗿𝘀𝗲𝗻𝗮𝗹.', '2014-07-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/291480/a5d53fd96d3f04a4d92e3c71a74e5061db8cc186/header.jpg?t=1772125417', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/291480/936d29f43ae14bad824555ce651511f5619e50b0/capsule_231x87.jpg?t=1772125417', '4'),
(294100, 'RimWorld', 'Ludeon Studios', 'Ludeon Studios', 'A sci-fi colony sim driven by an intelligent AI storyteller. Generates stories by simulating psychology, ecology, gunplay, melee combat, climate, biomes, diplomacy, interpersonal relationships, art, medicine, trade, and more.', '2018-10-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/294100/76e0613b8197327299d5dbabb0a7fd7828a689a2/header.jpg?t=1779909293', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/294100/a805ac5e3ceb54a2d7d3e1c1049907f1ef8bbb89/capsule_231x87.jpg?t=1779909293', '4'),
(311340, 'METAL GEAR SOLID V: GROUND ZEROES', 'KONAMI', 'KONAMI', 'World-renowned Kojima Productions brings the Metal Gear Solid franchise to Steam with METAL GEAR SOLID V: GROUND ZEROES. Play as the legendary hero Snake and infiltrate a Cuban military base to rescue the hostages. Can you make it out alive?', '2014-12-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/311340/header.jpg?t=1718869217', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/311340/capsule_231x87.jpg?t=1718869217', '4'),
(322170, 'Geometry Dash', 'RobTop Games', 'RobTop Games', 'Jump and fly your way through danger in this rhythm-based action platformer!', '2014-12-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/header.jpg?t=1775300400', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/capsule_231x87.jpg?t=1775300400', '4'),
(322330, 'Don\'t Starve Together', 'Klei Entertainment', 'Klei Entertainment', 'Fight, Farm, Build and Explore Together in the standalone multiplayer expansion to the uncompromising wilderness survival game, Don\'t Starve.', '2016-04-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322330/14496a5926156fbaf8b026f8224ba8c34e9b5096/header_alt_assets_49.jpg?t=1777913126', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322330/72c1dd65c4c7b66a3bf3cba525230e94218d3d97/capsule_231x87_alt_assets_49.jpg?t=1777913126', '4'),
(346110, 'ARK: Survival Evolved', 'Studio Wildcard, Instinct Game', 'Studio Wildcard, Snail Games U', 'Stranded on the shores of a mysterious island, you must learn to survive. Use your cunning to kill or tame the primeval creatures roaming the land, and encounter other players to survive, dominate... and escape!', '2017-08-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/346110/header.jpg?t=1765677889', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/346110/capsule_231x87.jpg?t=1765677889', '3'),
(352400, 'LEGO® Jurassic World', 'TT Games Ltd', 'Warner Bros. Interactive Enter', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as the highly anticipated Jurassic World, LEGO Jurassic World™ is the first videogame where players will be able to relive and experience all four Jurassic films.', '2015-06-11', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/352400/header.jpg?t=1745540350', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/352400/capsule_231x87.jpg?t=1745540350', '3'),
(356190, 'Middle-earth™: Shadow of War™', 'Monolith Productions', 'WB Games', 'Experience an epic open-world brought to life by the award-winning Nemesis System. Forge a new Ring of Power, conquer Fortresses in massive battles and dominate Mordor with your personal orc army in Middle-earth™: Shadow of War™.', '2017-10-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/356190/header.jpg?t=1747346596', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/356190/capsule_231x87.jpg?t=1747346596', '4'),
(365590, 'Tom Clancy’s The Division™', 'Massive Entertainment', 'Ubisoft', 'A tactical open world third-person shooter set in New York after a deadly pandemic. Team up or go solo to restore order against deadly factions, secure loot, and conquer high-risk endgame challenges.', '2016-03-07', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/365590/e36fd6a73af2b20d6286633ee3a089acf53397ff/header.jpg?t=1770141394', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/365590/669d04e17f4f30a6e1eaab016956dc09ab23ea0d/capsule_231x87.jpg?t=1770141394', '4'),
(370910, 'Kathy Rain', 'Clifftop Games', 'Raw Fury', 'Set in the \'90s, Kathy Rain tells the story of a strong-willed journalism major who has to come to terms with her troubled past as she investigates the mysterious death of her recently deceased grandfather.', '2016-05-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/370910/header.jpg?t=1726577236', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/370910/capsule_231x87.jpg?t=1726577236', '4'),
(381210, 'Dead by Daylight', 'Behaviour Interactive Inc.', 'Behaviour Interactive Inc.', '10 years of horror. 10 years of jump scares and close calls. 10 years of brutal sacrifices and thrilling escapes. Trapped forever in a realm of eldritch evil where even death is not an escape, four determined Survivors face a bloodthirsty Killer in a vicious game of nerve and wits.', '2016-06-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/381210/8512297f0f02ec3e592f45b21779f61624941964/header_alt_assets_6.jpg?t=1778880603', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/381210/2c90430e51332137ca52f85da8cfc83e40755d7e/capsule_231x87_alt_assets_6.jpg?t=1778880603', '4'),
(391540, 'Undertale', 'tobyfox', 'tobyfox', 'UNDERTALE! The RPG game where you don\'t have to destroy anyone.', '2015-09-15', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/391540/header.jpg?t=1757349115', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/391540/capsule_231x87.jpg?t=1757349115', '5'),
(394360, 'Hearts of Iron IV', 'Paradox Development Studio', 'Paradox Interactive', 'Victory is at your fingertips! Your ability to lead your nation is your supreme weapon, the strategy game Hearts of Iron IV lets you take command of any nation in World War II; the most engaging conflict in world history.', '2016-06-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/394360/67bbd0057627fc2244793bcdd09260c2539499cf/header.jpg?t=1779837014', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/394360/08a0a8f6c28071017611aa39b835c193a27f2518/capsule_231x87.jpg?t=1779837014', '4'),
(413150, 'Stardew Valley', 'ConcernedApe', 'ConcernedApe', 'You\'ve inherited your grandfather\'s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home?', '2016-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/header.jpg?t=1754692865', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/capsule_231x87.jpg?t=1754692865', '4'),
(424840, 'Little Nightmares', 'Tarsier Studios', 'BANDAI NAMCO Entertainment', 'Take on the role of Six, a lone child lost in a massive metal vessel known as the Maw, surrounded by dangerous, distorted versions of adults. You’ll need to do your best to escape in one piece or your fate will be worse than you ever dared dream.', '2017-04-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/424840/facf9a7a675c6d7f210d96d6b111caffe0386cd5/header.jpg?t=1773135169', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/424840/2bdbdbe316dba829ab67ea61528ab87a156fc2ed/capsule_231x87.jpg?t=1773135169', '4'),
(431960, 'Wallpaper Engine', 'Wallpaper Engine Team', 'Wallpaper Engine Team', 'Use stunning live wallpapers on your desktop. Animate your own images to create new wallpapers or import videos/websites and share them on the Steam Workshop!', '2018-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/header.jpg?t=1779452230', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/capsule_231x87.jpg?t=1779452230', '4'),
(433340, 'Slime Rancher', 'Monomi Park', 'Monomi Park', 'Slime Rancher is the tale of Beatrix LeBeau, a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ‘Far, Far Range’ where she tries her hand at making a living wrangling slimes.', '2017-08-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/433340/header.jpg?t=1758651509', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/433340/capsule_231x87.jpg?t=1758651509', '4'),
(440900, 'Conan Exiles Enhanced', 'Funcom, Inflexion Games', 'Funcom', 'Conan Exiles Enhanced is an open world survival game set in the mythical lands of Hyboria, now fully upgraded to Unreal Engine 5 with stunning visuals and improved performance. SURVIVE, BUILD, and DOMINATE alone or with friends in a world brimming with adventure!', '2018-05-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440900/b49106f92fc749db3710622258d00eb9576ecaff/header_alt_assets_7.jpg?t=1778144715', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440900/e306c9c1b85d6cbca8f1a132f0888b7163d9b3b1/capsule_231x87_alt_assets_7.jpg?t=1778144715', '4'),
(466240, 'Deceit', 'World Makers', 'World Makers', 'Test your instincts at trust and deception in an action-filled, multiplayer first-person shooter. You wake up in unknown surroundings to the sound of the Game Master’s unfamiliar voice, surrounded by five others. A third of your group have been infected with a virus, but who will escape?', '2017-03-03', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/466240/header.jpg?t=1762432934', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/466240/capsule_231x87.jpg?t=1762432934', '4'),
(489830, 'The Elder Scrolls V: Skyrim Special Edition', 'Bethesda Game Studios', 'Bethesda Softworks', 'Winner of more than 200 Game of the Year Awards, The Elder Scrolls V: Skyrim Special Edition brings the epic fantasy to life in stunning detail. The Special Edition includes the critically acclaimed game and add-ons with all-new features.', '2016-10-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/489830/header.jpg?t=1753715778', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/489830/capsule_231x87.jpg?t=1753715778', '3'),
(518790, 'theHunter: Call of the Wild™', 'Expansive Worlds', 'Avalanche Studios', 'Discover an atmospheric hunting game like no other in this realistic, stunning open world – regularly updated in collaboration with the community. Immerse yourself in the single player campaign, or share the ultimate hunting experience with friends.', '2017-02-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/518790/00f0df3558439a6a2cc4fbd7a658b00fb71353ea/header.jpg?t=1776175310', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/518790/599d7d90d73a8a5ca08d7a0413c2487a6334c250/capsule_231x87.jpg?t=1776175310', '4'),
(553850, 'HELLDIVERS™ 2', 'Arrowhead Game Studios', 'PlayStation Publishing LLC', 'The Galaxy’s Last Line of Offence. Enlist in the Helldivers and join the fight for freedom across a hostile galaxy in a fast, frantic, and ferocious third-person shooter.', '2024-02-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/553850/f11c258b04a5e3e7771c1bab60f324ebf6c6c6fb/header.jpg?t=1779899567', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/553850/8463c7dc0ff0c0e3eef6de1688ea25f081761c99/capsule_231x87.jpg?t=1779899567', '4'),
