(960090, 'Bloons TD 6', 'Ninja Kiwi', 'Ninja Kiwi', 'The Bloons are back and better than ever! Get ready for a massive 3D tower defense game designed to give you hours and hours of the best strategy gaming available.', '2018-12-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/960090/header.jpg?t=1769161752', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/960090/capsule_231x87.jpg?t=1769161752', '4'),
(1063730, 'New World: Aeternum', 'Amazon Game Studios', 'Amazon Game Studios', 'Experience a thrilling action RPG set on the supernatural island of Aeternum. Forge your destiny on an adventure filled with danger and opportunity.', '2021-09-28', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1063730/bd98bbdc4fdf388d07afa6ec8d781cb863bccfb0/header.jpg?t=1768500124', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1063730/2fe94eba6734521fbd4f44fb23ea66cb79376067/capsule_231x87.jpg?t=1768500124', '4'),
(1086940, 'Baldur\'s Gate 3', 'Larian Studios', 'Larian Studios', 'Baldur’s Gate 3 is a story-rich, party-based RPG set in the universe of Dungeons &amp; Dragons, where your choices shape a tale of fellowship and betrayal, survival and sacrifice, and the lure of absolute power.', '2023-08-03', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1086940/48a2fcbda8565bb45025e98fd8ebde8a7203f6a0/header.jpg?t=1777363040', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1086940/3dd81008e9c385caf68152450c22353f6a8abec9/capsule_231x87.jpg?t=1777363040', '5'),
(1091500, 'Cyberpunk 2077', 'CD PROJEKT RED', 'CD PROJEKT RED', 'Cyberpunk 2077 is an open-world, action-adventure RPG set in the dark future of Night City — a dangerous megalopolis obsessed with power, glamor, and ceaseless body modification.', '2020-12-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1091500/e9047d8ec47ae3d94bb8b464fb0fc9e9972b4ac7/header.jpg?t=1769690377', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1091500/590e0988a2fb79f44d3e31e41fd4949eb76abc41/capsule_231x87.jpg?t=1769690377', '4'),
(1142710, 'Total War: WARHAMMER III', 'CREATIVE ASSEMBLY, Feral Inter', 'SEGA, Feral Interactive', 'The cataclysmic conclusion to the Total War: WARHAMMER trilogy is here. Rally your forces and step into the Realm of Chaos, a dimension of mind-bending horror where the very fate of the world will be decided. Will you conquer your Daemons… or command them?', '2022-02-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1142710/header.jpg?t=1779441058', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1142710/capsule_231x87.jpg?t=1779441058', '4'),
(1144200, 'Ready or Not', 'VOID Interactive', 'VOID Interactive', 'Ready or Not is an intense, tactical, first-person shooter that depicts a modern-day world in which SWAT police units are called to defuse hostile and confronting situations.', '2023-12-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1144200/317bd08eeca2cd880bc723d34ebde9c99c53be52/header_alt_assets_0.jpg?t=1779907126', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1144200/b30c23f2ed6bb199a0ee33ef8e78ab25bcc1b050/capsule_231x87_alt_assets_0.jpg?t=1779907126', '4'),
(1158310, 'Crusader Kings III', 'Paradox Development Studio', 'Paradox Interactive', 'Love, fight, scheme, and claim greatness. Determine your noble house’s legacy in the sprawling grand strategy of Crusader Kings III. Death is only the beginning as you guide your dynasty’s bloodline in the rich and larger-than-life simulation of the Middle Ages.', '2020-09-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1158310/8a7e814d13f8e73c0d40471f585ece908f9be282/header.jpg?t=1777568423', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1158310/969346b7534d84360e80d8997c3f58636140893f/capsule_231x87.jpg?t=1777568423', '5'),
(1167630, 'Teardown', 'Tuxedo Labs', 'Tuxedo Labs', 'Prepare the perfect heist in a fully destructible, simulated voxel world. Tear down walls with vehicles or use explosives to create your own shortcuts. Shape the environment to your advantage in the most creative ways you can imagine. Play solo or with up to 12 players in multiplayer.', '2022-04-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1167630/0e7e93896986a74b8a0394318e92e8f2789abd5d/header_alt_assets_5.jpg?t=1779880867', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1167630/84cdc9c69746daeee59a56b5269596ebbdb014fb/capsule_231x87_alt_assets_5.jpg?t=1779880867', '4'),
(1174180, 'Red Dead Redemption 2', 'Rockstar Games', 'Rockstar Games', 'Arthur Morgan and the Van der Linde Gang are outlaws on the run. With federal agents and bounty hunters massing on their heels, the gang must rob, steal, and fight their way across the rugged heartland in order to survive.', '2019-12-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1174180/header.jpg?t=1759502961', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1174180/capsule_231x87.jpg?t=1759502961', '5'),
(1222680, 'Need for Speed™ Heat', 'Ghost Games', 'Electronic Arts', 'Hustle by day and risk it all at night in Need for Speed™ Heat Deluxe Edition, a white-knuckle street racer, where the lines of the law fade as the sun starts to set.', '2020-06-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1222680/header.jpg?t=1777414224', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1222680/capsule_231x87.jpg?t=1777414224', '3'),
(1244460, 'Jurassic World Evolution 2', 'Frontier Developments', 'Frontier Developments', 'Jurassic World Evolution 2 is the much-anticipated sequel to Frontier’s highly successful Jurassic World Evolution. This bold new era in the Jurassic World Evolution game franchise builds upon the ground-breaking and immersive 2018 management simulation.', '2021-11-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1244460/header.jpg?t=1750957701', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1244460/capsule_231x87.jpg?t=1750957701', '4'),
(1245620, 'ELDEN RING', 'FromSoftware, Inc.', 'FromSoftware, Inc., Bandai Nam', 'THE CRITICALLY ACCLAIMED FANTASY ACTION RPG. Rise, Tarnished, and be guided by grace to brandish the power of the Elden Ring and become an Elden Lord in the Lands Between.', '2022-02-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1245620/header.jpg?t=1767883716', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1245620/capsule_231x87.jpg?t=1767883716', '5'),
(1262540, 'Need for Speed™', 'Ghost Games', 'Electronic Arts', 'Ready to own the streets? Get behind the wheel of iconic cars and floor it through Ventura Bay, a sprawling urban playground. Explore overlapping stories as you build your reputation – and your dream car – and become the ultimate racing icon.', '2020-06-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1262540/header.jpg?t=1777394657', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1262540/capsule_231x87.jpg?t=1777394657', '4'),
(1262560, 'Need for Speed™ Most Wanted', 'Criterion Games', 'Electronic Arts', 'The open-world action in Need for Speed Most Wanted gives you the freedom to drive your way. Hit jumps and shortcuts, switch cars, lie low or head for terrain that plays to your vehicle’s unique strengths. Fight your way past cops and rivals using skill, high-end car tech and tons of nitrous.', '2020-06-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1262560/header.jpg?t=1777484382', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1262560/capsule_231x87.jpg?t=1777484382', '4'),
(1293830, 'Forza Horizon 4', 'Playground Games', 'Xbox Game Studios', 'Dynamic seasons change everything at the world’s greatest automotive festival. Go it alone or team up with others to explore beautiful and historic Britain in a shared open world.', '2021-03-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1293830/header.jpg?t=1734336342', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1293830/capsule_231x87.jpg?t=1734336342', '4'),
(1326470, 'Sons Of The Forest', 'Endnight Games Ltd', 'Newnight', 'Sent to find a missing billionaire on a remote island, you find yourself in a cannibal-infested hellscape. Craft, build, and struggle to survive, alone or with friends, in this terrifying new open-world survival horror simulator.', '2024-02-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1326470/header.jpg?t=1708624856', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1326470/capsule_231x87.jpg?t=1708624856', '4'),
(1332010, 'Stray', 'BlueTwelve Studio', 'Annapurna Interactive', 'Lost, alone and separated from family, a stray cat must untangle an ancient mystery to escape a long-forgotten cybercity and find their way home.', '2022-07-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1332010/71daca1910d664d31240b9623a495e0c0828807f/header.jpg?t=1779927784', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1332010/01489897d641b7f2e734a436dfabdd74afd4c677/capsule_231x87.jpg?t=1779927784', '4');
INSERT INTO `games` (`id`, `title`, `developer`, `publisher`, `about`, `release_date`, `cover_img`, `icon`, `steam_rating`) VALUES
(1364780, 'Street Fighter™ 6', 'CAPCOM Co., Ltd.', 'CAPCOM Co., Ltd.', 'Here comes Capcom’s newest challenger! Street Fighter™ 6 launches worldwide on June 2nd, 2023 and represents the next evolution of the Street Fighter™ series! Street Fighter 6 spans three distinct game modes, including World Tour, Fighting Ground and Battle Hub.', '2023-06-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1364780/header.jpg?t=1779953790', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1364780/f7f38ca38076c9bdf010672bb7b071d66625d401/capsule_231x87_alt_assets_19.jpg?t=1779953790', '5'),
(1366800, 'Crosshair X', 'CenterPoint Gaming', 'CenterPoint Gaming', 'Improve your aim and accuracy in every shooter you play. Crosshair X overlays a custom crosshair on top of any game, even games that do not include one. Choose from thousands of community designs or build your own with the designer.', '2020-08-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1366800/22e1a703a4d8f45c900741b53a4f933862798a10/header.jpg?t=1779302642', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1366800/a316b8a709e0ca866266b6152d016146ae3fdc47/capsule_231x87.jpg?t=1779302642', '4'),
(1443810, 'Round 99', 'Boomz Games', 'Boomz Games', 'Round 99 is a fast-paced shooter combined with a platformer that focuses on jumping around colorful environments and making a variety of enemies explode! Jump around 12 levels and bombard nearly 20 different enemies and bosses alone or with friends.', '2020-12-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1443810/header.jpg?t=1626380790', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1443810/capsule_231x87.jpg?t=1626380790', '4'),
(1458140, 'Pacific Drive', 'Ironwood Studios', 'Kepler Interactive', 'Face the supernatural dangers of the Olympic Exclusion Zone with a car as your only lifeline in this driving survival adventure! Scavenge resources, load up your trusty station wagon, and drive like hell to make it through alive.', '2024-02-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1458140/3a5fa1e845c13b48f9e2ed042f4538ac62bd16ed/header.jpg?t=1763777212', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1458140/7c7238c946abefe1c7bc08e69f84af015e7c39ed/capsule_231x87.jpg?t=1763777212', '4'),
(1551360, 'Forza Horizon 5', 'Playground Games', 'Xbox Game Studios', 'Explore the vibrant open world landscapes of Mexico with limitless, fun driving action in the world’s greatest cars.', '2021-11-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1551360/header.jpg?t=1746471508', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1551360/capsule_231x87.jpg?t=1746471508', '4'),
(1623730, 'Palworld', 'Pocketpair', 'Pocketpair', 'Fight, farm, build and work alongside mysterious creatures called &quot;Pals&quot; in this completely new multiplayer, open world survival and crafting game!', '2024-01-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1623730/058bd87dc17a7179e07c446aa64d0574ca43ab9d/header.jpg?t=1779864445', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1623730/4f823e476ad290ad4f19763e7d800723df422dfa/capsule_231x87.jpg?t=1779864445', '4'),
(1659040, 'HITMAN World of Assassination', 'IO Interactive A/S', 'IO Interactive A/S', 'Enter the world of the ultimate assassin. HITMAN World of Assassination delivers the definitive stealth action experience, putting you in the shoes of Agent 47, a master assassin. Explore immersive locations, uncover hidden secrets, and eliminate targets with complete freedom of approach.', '2022-01-20', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1659040/c62446d5c95f583a296d7f1b99045a61e2f81dea/header.jpg?t=1780060872', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1659040/capsule_231x87.jpg?t=1780060872', '4'),
(1671210, 'DELTARUNE', 'tobyfox', 'tobyfox', 'Dive into the parallel story to UNDERTALE! Fight or spare your way through action-packed battles as you explore a mysterious world alongside an endearing cast of new and familiar characters. Chapters 1-4 will be available on launch, with more planned as free updates!', '2025-06-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1671210/7ccda5b1631d2e60cc756a3271e845dbb9168821/header.jpg?t=1749252480', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1671210/capsule_231x87.jpg?t=1749252480', '4'),
(1817070, 'Marvel’s Spider-Man Remastered', 'Insomniac Games, Nixxes Softwa', 'PlayStation Publishing LLC', 'In Marvel’s Spider-Man Remastered, the worlds of Peter Parker and Spider-Man collide in an original action-packed story. Play as an experienced Peter Parker, fighting big crime and iconic villains in Marvel’s New York. Web-swing through vibrant neighborhoods and defeat villains with epic takedowns.', '2022-08-12', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1817070/header.jpg?t=1763569047', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1817070/capsule_231x87.jpg?t=1763569047', '4'),
(1938090, 'Call of Duty®', 'Treyarch, Raven Software, Been', 'Activision', 'The Call of Duty® experience supports Modern Warfare® 4, Black Ops 7, Black Ops 6 and Call of Duty®: Warzone™.', '2022-10-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1938090/23af6cf41e2d09620caa07700a4cb3288dbcbaa8/header.jpg?t=1780070700', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1938090/0ac3cc02398b9db61c8db4fef2e3e1b4b8b66e4b/capsule_231x87.jpg?t=1780070700', '4'),
(1966720, 'Lethal Company', 'Zeekerss', 'Zeekerss', 'A co-op horror about scavenging at abandoned moons to sell scrap to the Company.', '2023-10-23', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1966720/header.jpg?t=1775380053', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1966720/capsule_231x87.jpg?t=1775380053', '4'),
(2050650, 'Resident Evil 4', 'CAPCOM Co., Ltd.', 'CAPCOM Co., Ltd.', 'Survival is just the beginning. Six years have passed since the biological disaster in Raccoon City. Leon S. Kennedy, one of the survivors, tracks the president\'s kidnapped daughter to a secluded European village, where there is something terribly wrong with the locals.', '2023-03-23', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2050650/header.jpg?t=1772502922', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2050650/capsule_231x87.jpg?t=1772502922', '5'),
(2131630, 'METAL GEAR SOLID - Master Collection Version', 'KONAMI', 'KONAMI', 'The first 3D title in the METAL GEAR series pioneering a new level of stealth action with live action footage, cinematic cut scenes, and innovative gameplay.', '2023-10-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131630/header.jpg?t=1737564028', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131630/capsule_231x87.jpg?t=1737564028', '4'),
(2131640, 'METAL GEAR SOLID 2: Sons of Liberty - Master Colle', 'KONAMI', 'KONAMI', 'The fourth game in the METAL GEAR series: set over two incidents in 2007 and 2009, featuring Solid Snake and Raiden, introducing new stealth gameplay features.', '2023-10-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131640/header.jpg?t=1737564625', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131640/capsule_231x87.jpg?t=1737564625', '4'),
(2131650, 'METAL GEAR SOLID 3: Snake Eater - Master Collectio', 'KONAMI', 'KONAMI', 'Metal Gear Solid 3: Snake Eater is the origin story of Naked Snake and his mentor The Boss and the fifth title in the METAL GEAR series.', '2023-10-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131650/header.jpg?t=1737564722', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2131650/capsule_231x87.jpg?t=1737564722', '4'),
(2215200, 'LEGO® Batman™: Legacy of the Dark Knight', 'TT Games', 'Warner Bros. Games, Warner Bro', 'Rise as the Dark Knight and experience the essential Batman story in a bold, action-packed adventure with hard-hitting combat, an open-world Gotham City, and the signature LEGO charm that fans know and love.', '2026-05-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2215200/a07a9a6c0c9c1225f5b260b4f29fe40e6f099f6b/header.jpg?t=1779824566', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2215200/4933722fc48c284f30ea2d0f9eb932c0ab3de1b5/capsule_231x87.jpg?t=1779824566', '4'),
(2246340, 'Monster Hunter Wilds', 'CAPCOM Co., Ltd.', 'CAPCOM Co., Ltd.', 'The unbridled force of nature runs wild and relentless, with environments transforming drastically from one moment to the next. This is a story of monsters and humans and their struggles to live in harmony in a world of duality.', '2025-02-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2246340/header.jpg?t=1771382452', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2246340/970508d58e4f11f6f9ff3e2921b7eec558a50af8/capsule_231x87.jpg?t=1771382452', '4'),
(2300320, 'Farming Simulator 25', 'GIANTS Software', 'GIANTS Software', 'Farming Simulator 25 invites you to join the rewarding farm life, single-handedly or cooperatively in multiplayer. This Farm is Your Farm!', '2024-11-12', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2300320/c2a205133d23cd24faf3c152d972a1d0177661b8/header.jpg?t=1775646645', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2300320/f56e9279a16ad2f6a0532a7ef72042d7428c00c7/capsule_231x87.jpg?t=1775646645', '4'),
(2344520, 'Diablo® IV', 'Blizzard Entertainment, Inc.', 'Blizzard Entertainment, Inc.', 'Join the fight for Sanctuary in Diablo® IV, the ultimate action RPG adventure. Experience the critically acclaimed campaign and new seasonal content.', '2023-10-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2344520/80f21a42e378b93e8fbb68ee43103be8ab84891b/header.jpg?t=1777501665', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2344520/7086c858ce766d047bf357515805eda229d966b0/capsule_231x87.jpg?t=1777501665', '4'),
(2358720, 'Black Myth: Wukong', 'Game Science', 'Game Science', 'Black Myth: Wukong is an action RPG rooted in Chinese mythology. You shall set out as the Destined One to venture into the challenges and marvels ahead, to uncover the obscured truth beneath the veil of a glorious legend from the past.', '2024-08-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2358720/header.jpg?t=1760601605', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2358720/b7f722ddd5e23503f598586aa3700dd4d827bb2d/capsule_231x87.jpg?t=1760601605', '4'),
(2379780, 'Balatro', 'LocalThunk', 'Playstack', 'The poker roguelike. Balatro is a hypnotically satisfying deckbuilder where you play illegal poker hands, discover game-changing jokers, and trigger adrenaline-pumping, outrageous combos.', '2024-02-20', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2379780/7a85430784e4d613cdb0547414d8cf16ffa45747/header.jpg?t=1779304872', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2379780/554b5f66f60e80b43f910cba21d23af16ed897be/capsule_231x87.jpg?t=1779304872', '5'),
(2417610, 'METAL GEAR SOLID Δ: SNAKE EATER', 'KONAMI', 'KONAMI', 'A remake of the 2004 game METAL GEAR SOLID 3: SNAKE EATER, with the same gripping story and engrossing world, now with all new graphics and 3D audio that enhance the jungle atmosphere. Get ready for the ultimate survival stealth action experience.', '2025-08-28', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2417610/05c97cbcd0cfc27c8ed6c7fc6d81e0995aa2a7d4/header.jpg?t=1762249119', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2417610/fcf468fafa62aa13ac11f1ad2f84cab740eac6af/capsule_231x87.jpg?t=1762249119', '4'),
(2483190, 'Forza Horizon 6', 'Playground Games', 'Xbox Game Studios', 'Discover the breathtaking landscapes of Japan in over 550 real-world cars and become a racing Legend in Forza Horizon\'s biggest open world driving adventure yet.', '2026-05-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2483190/27abb1584a118d50d0e3950fd48d557c51981db7/header.jpg?t=1779912021', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2483190/d0d73e4ff499d6cd6fb06f7af898414179997125/capsule_231x87.jpg?t=1779912021', '4'),
(2622380, 'ELDEN RING NIGHTREIGN', 'FromSoftware, Inc.', 'FromSoftware, Inc., Bandai Nam', 'ELDEN RING NIGHTREIGN is a standalone adventure within the ELDEN RING universe, crafted to offer players a new gaming experience by reimagining the game’s core design.', '2025-05-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2622380/header.jpg?t=1773099036', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2622380/8ebc4260af27bc55ba8b88982fd7eb7f970d43c9/capsule_231x87.jpg?t=1773099036', '4'),
(2670630, 'Supermarket Simulator', 'Nokta Games', 'Nokta Games', 'Run your own supermarket! Stock shelves, set your prices, take payments, hire staff, expand your store, handle shoplifters, and design your layout. Purchase goods from online or local markets around town, and personally deliver online orders to your customers.', '2025-06-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2670630/267eef055b0e5d45cb1c874f816a31dded4bb88e/header.jpg?t=1778755926', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2670630/af5b359eff1a63720c22eb691a190501b5568571/capsule_231x87.jpg?t=1778755926', '4'),
(2694490, 'Path of Exile 2', 'Grinding Gear Games', 'Grinding Gear Games', 'Path of Exile 2 is a next generation Action RPG from Grinding Gear Games, featuring co-op for up to six players. Set years after the original Path of Exile, you will return to the dark world of Wraeclast and seek to end the corruption that is spreading.', '2024-12-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2694490/24eeddcbda17903f03d819588757e40845f8115f/header.jpg?t=1779752119', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2694490/bae62b5ac9eeb900458e3f6c089bf5df3eb923c9/capsule_231x87.jpg?t=1779752119', '4'),
(2958130, 'Jurassic World Evolution 3', 'Frontier Developments', 'Frontier Developments', 'Build your own Jurassic World. Nurture generations of dinosaurs with the series debut of juveniles, create and manage sprawling prehistoric parks around the globe, and let your imagination roar with powerful new creative options.', '2025-10-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2958130/df39f8c59232633e8e01ab63313b095402bdd0d5/header.jpg?t=1770121149', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2958130/767bbed48a0426d14562f4aba32bd30abefb79ec/capsule_231x87.jpg?t=1770121149', '4'),
(3164500, 'Schedule I', 'TVGS', 'TVGS', 'From small-time dope pusher to kingpin - manufacture and distribute a range of drugs throughout the grungy city of Hyland Point. Expand your empire with properties, businesses, employees and more.', '2025-03-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3164500/header.jpg?t=1773974661', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3164500/986ee9a7a25cb0e61d1530cc3cd7e3e06aa68733/capsule_231x87.jpg?t=1773974661', '4'),
(3240220, 'Grand Theft Auto V Enhanced', 'Rockstar North', 'Rockstar Games', 'Experience entertainment blockbusters Grand Theft Auto V and Grand Theft Auto Online — now upgraded for a new generation with stunning visuals, faster loading, 3D audio, and more, plus exclusive content for GTA Online players.', '2025-03-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3240220/header.jpg?t=1765479644', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3240220/a318bd9affe8eee32984b18794b273c256e9b2d6/capsule_231x87.jpg?t=1765479644', '4'),
(3241660, 'R.E.P.O.', 'semiwork', 'semiwork', 'An online co-op horror game with up to 6 players. Locate valuable, fully physics-based objects and handle them with care as you retrieve and extract to satisfy your creator\'s desires.', '2025-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/a12c92856b71315da885924ea5e1d5290c8025b8/header_alt_assets_2.jpg?t=1778158882', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/e29789d09be972ea786975695bdde1cc047a76e1/capsule_231x87_alt_assets_2.jpg?t=1778158882', '4'),
(3768760, '007 First Light', 'IO Interactive A/S', 'IO Interactive A/S', 'Earn the Number. 007 First Light is a thrilling espionage action-adventure game from IO Interactive. Follow James Bond as a young, resourceful and sometimes reckless recruit in MI6\'s training programme, and discover an origin story of the world’s most famous spy.', '2026-05-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3768760/dbe86ebd2edb4c77d113e9e2feefeb90189fabc9/header.jpg?t=1780082026', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3768760/244e00f17e6d0b5d1e88320dfbb5a12b483be700/capsule_231x87.jpg?t=1780082026', '4');
